2812                       const TargetLibraryInfo &RunTLI, AAResults &RunAA,
2813                       MemoryDependenceResults *RunMD, LoopInfo &LI,
2814                       OptimizationRemarkEmitter *RunORE, MemorySSA *MSSA) {
2815   AC = &RunAC;
2816   DT = &RunDT;
2817   VN.setDomTree(DT);
2818   TLI = &RunTLI;
2819   VN.setAliasAnalysis(&RunAA);
2820   MD = RunMD;
2821   ImplicitControlFlowTracking ImplicitCFT;
2822   ICF = &ImplicitCFT;
2823   this->LI = &LI;
2824   VN.setMemDep(MD);
2825   VN.setMemorySSA(MSSA);
2826   ORE = RunORE;
2827   InvalidBlockRPONumbers = true;
2828   MemorySSAUpdater Updater(MSSA);
2829   MSSAU = MSSA ? &Updater : nullptr;
2830 
2831   bool Changed = false;
2832   bool ShouldContinue = true;
2833 
2834   DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Lazy);
2835   // Merge unconditional branches, allowing PRE to catch more
2836   // optimization opportunities.
2837   for (BasicBlock &BB : make_early_inc_range(F)) {
2838     bool RemovedBlock = MergeBlockIntoPredecessor(&BB, &DTU, &LI, MSSAU, MD);
2839     if (RemovedBlock)
2840       ++NumGVNBlocks;
2841 
2842     Changed |= RemovedBlock;
2843   }
2844   DTU.flush();
2845 
2846   unsigned Iteration = 0;
2847   while (ShouldContinue) {
2848     LLVM_DEBUG(dbgs() << "GVN iteration: " << Iteration << "\n");
