2882 bool GVNPass::processBlock(BasicBlock *BB) {
2883   if (DeadBlocks.count(BB))
2884     return false;
2885 
2886   bool ChangedFunction = false;
2887 
2888   // Since we may not have visited the input blocks of the phis, we can't
2889   // use our normal hash approach for phis.  Instead, simply look for
2890   // obvious duplicates.  The first pass of GVN will tend to create
2891   // identical phis, and the second or later passes can eliminate them.
2892   SmallPtrSet<PHINode *, 8> PHINodesToRemove;
2893   ChangedFunction |= EliminateDuplicatePHINodes(BB, PHINodesToRemove);
2894   for (PHINode *PN : PHINodesToRemove) {
2895     removeInstruction(PN);
2896   }
2897   for (Instruction &Inst : make_early_inc_range(*BB))
2898     ChangedFunction |= processInstruction(&Inst);
2899   return ChangedFunction;
2900 }
