2902 // Instantiate an expression in a predecessor that lacked it.
2903 bool GVNPass::performScalarPREInsertion(Instruction *Instr, BasicBlock *Pred,
2904                                         BasicBlock *Curr, unsigned int ValNo) {
2905   // Because we are going top-down through the block, all value numbers
2906   // will be available in the predecessor by the time we need them.  Any
2907   // that weren't originally present will have been instantiated earlier
2908   // in this loop.
2909   bool Success = true;
2910   for (unsigned I = 0, E = Instr->getNumOperands(); I != E; ++I) {
2911     Value *Op = Instr->getOperand(I);
2912     if (isa<Argument>(Op) || isa<Constant>(Op) || isa<GlobalValue>(Op))
2913       continue;
2914     // This could be a newly inserted instruction, in which case, we won't
2915     // find a value number, and should give up before we hurt ourselves.
2916     // FIXME: Rewrite the infrastructure to let it easier to value number
2917     // and process newly inserted instructions.
2918     if (!VN.exists(Op)) {
2919       Success = false;
2920       break;
2921     }
2922     uint32_t TValNo =
2923         VN.phiTranslate(Pred, Curr, VN.lookup(Op), *this);
2924     if (Value *V = findLeader(Pred, TValNo)) {
2925       Instr->setOperand(I, V);
2926     } else {
2927       Success = false;
2928       break;
2929     }
2930   }
2931 
2932   // Fail out if we encounter an operand that is not available in
2933   // the PRE predecessor.  This is typically because of loads which
2934   // are not value numbered precisely.
2935   if (!Success)
2936     return false;
2937 
2938   Instr->insertBefore(Pred->getTerminator()->getIterator());
2939   Instr->setName(Instr->getName() + ".pre");
2940   Instr->setDebugLoc(Instr->getDebugLoc());
2941 
2942   ICF->insertInstructionTo(Instr, Pred);
2943 
2944   unsigned Num = VN.lookupOrAdd(Instr);
2945   VN.add(Instr, Num);
2946 
2947   // Update the availability map to include the new instruction.
2948   LeaderTable.insert(Num, Instr, Pred);
2949   return true;
2950 }
