4122 /// Return true if it is known that V1 != V2.
4123 static bool isKnownNonEqual(const Value *V1, const Value *V2,
4124                             const APInt &DemandedElts, const SimplifyQuery &Q,
4125                             unsigned Depth) {
4126   if (V1 == V2)
4127     return false;
