2810 /// runOnFunction - This is the main transformation entry point for a function.
2811 bool GVNPass::runImpl(Function &F, AssumptionCache &RunAC, DominatorTree &RunDT,
2812                       const TargetLibraryInfo &RunTLI, AAResults &RunAA,
2813                       MemoryDependenceResults *RunMD, LoopInfo &LI,
2814                       OptimizationRemarkEmitter *RunORE, MemorySSA *MSSA) {
2815   AC = &RunAC;
2816   DT = &RunDT;
2817   VN.setDomTree(DT);
2818   TLI = &RunTLI;
2819   VN.setAliasAnalysis(&RunAA);
2820   MD = RunMD;
2821   ImplicitControlFlowTracking ImplicitCFT;
2822   ICF = &ImplicitCFT;
2823   this->LI = &LI;
2824   VN.setMemDep(MD);
2825   VN.setMemorySSA(MSSA);
2826   ORE = RunORE;
2827   InvalidBlockRPONumbers = true;
2828   MemorySSAUpdater Updater(MSSA);
2829   MSSAU = MSSA ? &Updater : nullptr;
2830 
2831   bool Changed = false;
2832   bool ShouldContinue = true;
2833 
2834   DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Lazy);
2835   // Merge unconditional branches, allowing PRE to catch more
2836   // optimization opportunities.
2837   for (BasicBlock &BB : make_early_inc_range(F)) {
2838     bool RemovedBlock = MergeBlockIntoPredecessor(&BB, &DTU, &LI, MSSAU, MD);
2839     if (RemovedBlock)
2840       ++NumGVNBlocks;
2841 
2842     Changed |= RemovedBlock;
2843   }
2844   DTU.flush();
2845 
2846   unsigned Iteration = 0;
2847   while (ShouldContinue) {
2848     LLVM_DEBUG(dbgs() << "GVN iteration: " << Iteration << "\n");
2849     (void) Iteration;
2850     ShouldContinue = iterateOnFunction(F);
2851     Changed |= ShouldContinue;
2852     ++Iteration;
2853   }
2854 
2855   if (isPREEnabled()) {
2856     // Fabricate val-num for dead-code in order to suppress assertion in
2857     // performPRE().
2858     assignValNumForDeadCode();
2859     bool PREChanged = true;
2860     while (PREChanged) {
2861       PREChanged = performPRE(F);
2862       Changed |= PREChanged;
2863     }
2864   }
2865 
2866   // FIXME: Should perform GVN again after PRE does something.  PRE can move
2867   // computations into blocks where they become fully redundant.  Note that
2868   // we can't do this until PRE's critical edge splitting updates memdep.
2869   // Actually, when this happens, we should just fully integrate PRE into GVN.
2870 
2871   cleanupGlobalSets();
2872   // Do not cleanup DeadBlocks in cleanupGlobalSets() as it's called for each
2873   // iteration.
2874   DeadBlocks.clear();
2875 
2876   if (MSSA && VerifyMemorySSA)
2877     MSSA->verifyMemorySSA();
2878 
2879   return Changed;
2880 }
